func TestWorkerDispatchAdapterStopWorkerUsesWorkerManagerStop(t *testing.T) {
	root := t.TempDir()
	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	require.NoError(t, os.MkdirAll(filepath.Join(m.rootDir, "worker-graphql-stop"), 0o755))
