// drainProgress reads ProgressEvents from ch and:
//  1. Updates the WorkerRecord's CurrentAttempt, RecentPhases, and LastAttempt fields.
//  2. Broadcasts each event to all active SSE subscribers for the worker.
//
// It runs as a goroutine alongside runWorker; it exits when ch is closed.
func (m *WorkerManager) drainProgress(workerID string, handle *workerHandle, ch <-chan agent.ProgressEvent) {
	const maxRecentPhases = 20
	for evt := range ch {
		m.mu.Lock()
		rec := handle.record

		// Substate signals (ddx-dc157075 AC #5). loop.idle marks the worker as
		// "idle" without disturbing CurrentAttempt; loop.active clears it when
		// the loop picks up the next candidate. These are not real attempt
		// phases, so they bypass the normal RecentPhases / CurrentAttempt path.
		switch evt.Phase {
		case "loop.idle":
			rec.Substate = "idle"
			handle.record = rec
			m.mu.Unlock()
			continue
		case "loop.active":
			rec.Substate = ""
			handle.record = rec
			m.mu.Unlock()
			continue
		}

		if !evt.Heartbeat {
			// Phase-transition: record in RecentPhases (capped at maxRecentPhases)
			rec.RecentPhases = append(rec.RecentPhases, PhaseTransition{
				Phase:    evt.Phase,
				TS:       evt.TS,
				PhaseSeq: evt.PhaseSeq,
			})
			if len(rec.RecentPhases) > maxRecentPhases {
				rec.RecentPhases = rec.RecentPhases[len(rec.RecentPhases)-maxRecentPhases:]
			}
			// Stamp lastPhaseTS so the watchdog can detect stalled attempts.
			handle.lastPhaseTS = evt.TS
		}

		if terminalPhases[evt.Phase] {
			// Increment live counters so Show() reflects progress before the
			// loop exits. runWorker will overwrite these with authoritative
			// loopResult values after progressDone is signalled, which is the
			// same value — so no double-counting occurs.
			rec.Attempts++
			if evt.Phase == "done" {
				rec.Successes++
			} else {
				rec.Failures++
			}

			// Move CurrentAttempt → LastAttempt
			if rec.CurrentAttempt != nil {
				rec.LastAttempt = &LastAttemptInfo{
					AttemptID: rec.CurrentAttempt.AttemptID,
					BeadID:    rec.CurrentAttempt.BeadID,
					Phase:     evt.Phase,
					StartedAt: rec.CurrentAttempt.StartedAt,
					EndedAt:   evt.TS,
					ElapsedMS: evt.ElapsedMS,
				}
			}
			rec.CurrentAttempt = nil
		} else {
			// Update or initialise CurrentAttempt
			if rec.CurrentAttempt == nil {
				rec.CurrentAttempt = &CurrentAttemptInfo{
					AttemptID: evt.AttemptID,
					BeadID:    evt.BeadID,
					StartedAt: evt.TS,
				}
			}
			rec.CurrentAttempt.AttemptID = evt.AttemptID
			rec.CurrentAttempt.BeadID = evt.BeadID

// fix (ddx-055e8d32): the gqlgen handler and resolver are built ONCE
// (lazily on first request) and reused across both /graphql and the scoped
// /api/projects/{project}/graphql route. Per-request reconstruction
// (LAYER 1) is no longer needed because resolver methods read WorkingDir
// from the request context rather than a struct field.
func (s *Server) serveGraphQL(w http.ResponseWriter, r *http.Request, workingDir string) {
	gqlServer := s.graphqlHandler()
	// Plumb the originating *http.Request into the resolver context so
	// resolvers (e.g. operatorPromptSubmit) can validate the CSRF header
	// and capture the originating identity from headers tsnetMiddleware
	// injects (X-Tailscale-User / X-Tailscale-Node). Also inject the
	// per-request workingDir so resolvers reading WorkingDir do so under
	// the scoped project (LAYER 2 / ddx-055e8d32) rather than the
	// resolver's startup default.
	ctx := r.Context()
	ctx = ddxgraphql.WithHTTPRequest(ctx, r)
	ctx = ddxgraphql.WithWorkingDir(ctx, workingDir)
	gqlServer.ServeHTTP(w, r.WithContext(ctx))
}

// graphqlHandler lazily builds and caches the gqlgen handler used by both
// /graphql and the scoped /api/projects/{project}/graphql route. The
// resolver's WorkingDir field is set to s.WorkingDir as the FALLBACK
// default; per-request scoping flows through context via WithWorkingDir
// (see serveGraphQL).
func (s *Server) graphqlHandler() http.Handler {
	s.gqlOnce.Do(func() {
		var fedProvider ddxgraphql.FederationProvider
		if s.hub != nil {
			fedProvider = newHubFederationProvider(s)
		}
		resolver := ddxgraphql.NewResolver()
		resolver.State = s.state
		resolver.WorkingDir = s.WorkingDir
		resolver.Workers = s.workers
		resolver.BeadBus = s.beadHub
		resolver.Actions = &workerDispatchAdapter{manager: s.workers}
		resolver.ExecLogs = &execLogAdapter{}
		resolver.CoordMetrics = &coordMetricsAdapter{reg: s.workers.LandCoordinators}
		resolver.CSRFTokens = s.csrfTokens
		resolver.OperatorPromptIdempotency = s.operatorPromptIdempotency
		resolver.OperatorPromptAutoApproveAllowlist = s.operatorPromptAutoApproveAllowlist
		resolver.PromptCapBytes = serverPromptCapBytes
		resolver.BuildSHA = serverBuildSHA()
		resolver.NodeID = s.state.Node.ID
		resolver.ExecuteLoopWaker = s.workers
		resolver.Federation = fedProvider
		resolver.ReportedWorkers = s.reportedWorkers
		resolver.ReviewSessions = newReviewPromptDecorator(ddxgraphql.NewInMemoryReviewSessionService())
		gqlServer := handler.New(ddxgraphql.NewExecutableSchema(ddxgraphql.Config{
			Resolvers:  resolver,
			Directives: ddxgraphql.DirectiveRoot{},
		}))
		gqlServer.AddTransport(transport.POST{})
		gqlServer.AddTransport(transport.GET{})
		gqlServer.AddTransport(transport.Websocket{
			Upgrader: websocket.Upgrader{
				CheckOrigin: func(r *http.Request) bool { return true },
			},
			KeepAlivePingInterval: 30 * time.Second,
		})
		s.gqlHandler = gqlServer
	})
	return s.gqlHandler
}

