// TestMain scrubs GIT_* environment variables so subprocess git calls in tests
// write to temp directories rather than the parent repository.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	cleanupTemp := isolateGraphQLTestTempRoot()
	code := m.Run()
	cleanupTemp()
	os.Exit(code)
}

func isolateGraphQLTestTempRoot() func() {
	tempRoot, err := os.MkdirTemp("", "ddx-server-graphql-tests-*")
	if err != nil {
		return func() {}
	}
	oldTmp, hadTmp := os.LookupEnv("TMPDIR")
	_ = os.Setenv("TMPDIR", tempRoot)
	return func() {
		if hadTmp {
			_ = os.Setenv("TMPDIR", oldTmp)
		} else {
			_ = os.Unsetenv("TMPDIR")
		}
		_ = os.RemoveAll(tempRoot)
	}
}

