// TestWorkerRecordShape verifies the WorkerRecord struct carries the FEAT-002
// required fields: CurrentAttempt, RecentPhases, and LastAttempt.
func TestWorkerRecordShape(t *testing.T) {
	// Zero value — all new fields must be nil/empty (omitempty)
	rec := WorkerRecord{ID: "w-1", Kind: "work", State: "running"}
	assert.Nil(t, rec.CurrentAttempt)
	assert.Empty(t, rec.RecentPhases)
	assert.Nil(t, rec.LastAttempt)

	// JSON round-trip: new fields are omitted when nil/empty
	data, err := json.Marshal(rec)
	require.NoError(t, err)
	assert.NotContains(t, string(data), "current_attempt")
	assert.NotContains(t, string(data), "recent_phases")
	assert.NotContains(t, string(data), "last_attempt")

	// JSON round-trip: new fields are present when set
	now := time.Now().UTC().Truncate(time.Second)
	rec.CurrentAttempt = &CurrentAttemptInfo{
		AttemptID: "20260414T000000-abcd1234",
		BeadID:    "ddx-abc123",
		Phase:     "running",
		PhaseSeq:  2,
		StartedAt: now,
		ElapsedMS: 5000,
	}
	rec.RecentPhases = []PhaseTransition{
		{Phase: "queueing", TS: now, PhaseSeq: 1},
		{Phase: "running", TS: now.Add(time.Second), PhaseSeq: 2},
	}

	data, err = json.Marshal(rec)
	require.NoError(t, err)
	assert.Contains(t, string(data), "current_attempt")
	assert.Contains(t, string(data), "recent_phases")

	var decoded WorkerRecord
	require.NoError(t, json.Unmarshal(data, &decoded))
	require.NotNil(t, decoded.CurrentAttempt)
	assert.Equal(t, "running", decoded.CurrentAttempt.Phase)
	assert.Equal(t, 2, decoded.CurrentAttempt.PhaseSeq)
	assert.Len(t, decoded.RecentPhases, 2)
	assert.Equal(t, "queueing", decoded.RecentPhases[0].Phase)
}

// TestDrainProgressUpdatesRecord verifies that drainProgress correctly
// updates WorkerRecord fields as ProgressEvents flow through the channel.
func TestDrainProgressUpdatesRecord(t *testing.T) {
	root := t.TempDir()
	m := NewWorkerManager(root)

	handle := &workerHandle{
		record: WorkerRecord{ID: "w-test", Kind: "work", State: "running"},
	}
	ch := make(chan agent.ProgressEvent, 10)

	go m.drainProgress("w-test", handle, ch)

	now := time.Now().UTC()

	// Send queueing transition
	ch <- agent.ProgressEvent{
		EventID: "evt-1", AttemptID: "atm-1", WorkerID: "w-test",
		BeadID: "ddx-1", Phase: "queueing", PhaseSeq: 1, Heartbeat: false,
		TS: now, ElapsedMS: 0,
	}
	// Send running transition
	ch <- agent.ProgressEvent{
		EventID: "evt-2", AttemptID: "atm-1", WorkerID: "w-test",
		BeadID: "ddx-1", Phase: "running", PhaseSeq: 2, Heartbeat: false,
		TS: now.Add(time.Second), ElapsedMS: 1000,
	}
	// Send heartbeat (should NOT go into RecentPhases)
	ch <- agent.ProgressEvent{
		EventID: "evt-3", AttemptID: "atm-1", WorkerID: "w-test",
		BeadID: "ddx-1", Phase: "running", PhaseSeq: 2, Heartbeat: true,
		TS: now.Add(2 * time.Second), ElapsedMS: 2000,
	}
	// Send terminal phase
	ch <- agent.ProgressEvent{
		EventID: "evt-4", AttemptID: "atm-1", WorkerID: "w-test",
		BeadID: "ddx-1", Phase: "done", PhaseSeq: 3, Heartbeat: false,
		TS: now.Add(3 * time.Second), ElapsedMS: 3000,
	}

	close(ch)

	// Wait for drainProgress goroutine to finish
	deadline := time.Now().Add(2 * time.Second)
	for time.Now().Before(deadline) {
		m.mu.Lock()
		phases := len(handle.record.RecentPhases)
		m.mu.Unlock()
		if phases == 3 { // queueing + running + done (heartbeat excluded)
			break
		}
		time.Sleep(10 * time.Millisecond)
	}

	m.mu.Lock()
	rec := handle.record
	m.mu.Unlock()

	// After terminal: CurrentAttempt is nil, LastAttempt is set
	assert.Nil(t, rec.CurrentAttempt, "CurrentAttempt should be nil after terminal phase")
	require.NotNil(t, rec.LastAttempt)

		}, nil
	})

	out, err := executeCommand(
		factory.NewRootCommand(),
		"work",
		"--ignore-cooldown",
		"--reason", "operator unblock",
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)
	require.NoError(t, err, "ddx work must drain cooled beads when override is explicit: %s", out)
	assert.Equal(t, []string{"cool-0", "cool-1", "cool-2", "cool-3", "cool-4"}, got)
}

// TestWork_NetworkFreeDrain_NoFetchInLoop verifies reliability principle P9:
// the drain loop's pre-claim hook never blocks on network I/O. The fixture
// repo has an origin remote whose URL points at a deleted path; the last
// observed refs/remotes/origin/main remains as a cached tip. A network-free
// drain must claim and execute a ready bead without error even though no
// `git fetch` against origin could succeed.
func TestWork_NetworkFreeDrain_NoFetchInLoop(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	gitEnv := gitpkg.CleanEnv()
	runGitEnv := func(dir string, args ...string) {
		t.Helper()
		c := exec.Command("git", args...)
		c.Dir = dir
		c.Env = gitEnv
		out, err := c.CombinedOutput()
		require.NoError(t, err, "git %v: %s", args, out)
	}

	originDir := t.TempDir()
	workDir := t.TempDir()
	runGitEnv(originDir, "init", "--bare", "-b", "main")
	runGitEnv(workDir, "clone", originDir, ".")
	runGitEnv(workDir, "config", "user.email", "test@ddx.test")
	runGitEnv(workDir, "config", "user.name", "DDx Test")
	require.NoError(t, os.WriteFile(filepath.Join(workDir, "seed.txt"), []byte("seed\n"), 0o644))
	runGitEnv(workDir, "add", "seed.txt")
	runGitEnv(workDir, "commit", "-m", "chore: initial seed")
	runGitEnv(workDir, "push", "-u", "origin", "main")

	// Break origin: point the remote URL at a deleted path and remove the bare
	// repo. refs/remotes/origin/main survives as the last-observed tip, so a
	// network-free ancestry check still resolves, but any fetch would fail.
	deletedOrigin := filepath.Join(t.TempDir(), "gone")
	runGitEnv(workDir, "remote", "set-url", "origin", "file://"+deletedOrigin)
	require.NoError(t, os.RemoveAll(originDir))

	seedExecuteBead(t, workDir, &bead.Bead{
		ID:        "ddx-network-free-drain",
		Title:     "network-free drain bead",
		Status:    bead.StatusOpen,
		Priority:  0,
		IssueType: bead.DefaultType,
	})

	var executed []string
	factory := NewCommandFactory(workDir)
	factory.AgentRunnerOverride = &tryHookRunnerStub{t: t}
	factory.tryExecutorOverride = agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
		executed = append(executed, beadID)
		return agent.ExecuteBeadReport{
			BeadID:    beadID,
			Status:    agent.ExecuteBeadStatusSuccess,
			ResultRev: "rev-" + beadID,
		}, nil
	})

	out, err := executeCommand(
		factory.NewRootCommand(),
		"work",
		"--once",
		"--project", workDir,
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)
	require.NoError(t, err, "network-free drain must claim and drain without origin reachability: %s", out)
	assert.Equal(t, []string{"ddx-network-free-drain"}, executed, "the ready bead must be claimed and executed")
}

type attemptBeadReaderFunc func(context.Context, string) (*bead.Bead, error)

func (f attemptBeadReaderFunc) Get(ctx context.Context, id string) (*bead.Bead, error) {
	return f(ctx, id)
}

func Test_WorkClaim_NotFoundRace(t *testing.T) {
	claimed := &bead.Bead{ID: "ddx-work-race-claim", Title: "Claimed bead"}

	var primaryCalls int
	primary := attemptBeadReaderFunc(func(ctx context.Context, id string) (*bead.Bead, error) {
		primaryCalls++
		return nil, fmt.Errorf("bead: not found: %s", id)
	})

	var refreshCalls int
	refreshed := attemptBeadReaderFunc(func(ctx context.Context, id string) (*bead.Bead, error) {
		refreshCalls++
		if id != claimed.ID {
			return nil, fmt.Errorf("bead: not found: %s", id)
		}
		return claimed, nil
	})

	got, err := resolveAttemptBead(context.Background(), claimed.ID, primary, func() attemptBeadReader {
		return refreshed
	}, nil)
	require.NoError(t, err)
	require.Same(t, claimed, got)
	assert.Equal(t, 1, primaryCalls, "primary lookup must miss once before refreshing")
	assert.Equal(t, 1, refreshCalls, "refresh lookup must retry exactly once")
}

