type logBuffer interface {
	io.Writer
	String() string
}

type lockedBuffer struct {
	mu  sync.Mutex
	buf bytes.Buffer
}

func newLockedBuffer() *lockedBuffer {
	return &lockedBuffer{}
}

func (b *lockedBuffer) Write(p []byte) (int, error) {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.buf.Write(p)
}

func (b *lockedBuffer) String() string {
	b.mu.Lock()
	defer b.mu.Unlock()
	return b.buf.String()
}

type managedWorkerCommandBuilderFunc func(projectRoot, workerID string, spec ExecuteLoopWorkerSpec) (*exec.Cmd, error)

func (m *WorkerManager) StartManagedExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}
	spec.ProjectRoot = effectiveRoot
	spec.ApplyDefaults()
	if err := spec.Validate(); err != nil {
		return WorkerRecord{}, err
	}

	// Managed workers are launched through the CLI child path, which already
	// treats route constraints opaquely. Force the same semantics here so the
	// persisted spec and child invocation match ddx work.
	spec.OpaquePassthrough = true

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepathJoin(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	specData, _ := json.MarshalIndent(spec, "", "  ")
	_ = os.WriteFile(filepathJoin(dir, "spec.json"), append(specData, '\n'), 0o644)

	logPath := filepathJoin(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return WorkerRecord{}, err
	}

	startedAt := time.Now().UTC()
	record := WorkerRecord{
		ID:          id,
		Kind:        "work",
		State:       "running",
		Status:      "running",
		ProjectRoot: effectiveRoot,
		Harness:     spec.Harness,
		Model:       spec.Model,
		Profile:     agent.NormalizeRoutingProfile(spec.Profile),
		Effort:      spec.Effort,
		Once:        executeLoopOnce(spec),
		PollInterval: executeLoopPollInterval(spec).String(),
		StdoutPath:   relToProject(m.projectRoot, logPath),
		SpecPath:     relToProject(m.projectRoot, filepathJoin(dir, "spec.json")),
		StartedAt:    startedAt,
		Lifecycle: []WorkerLifecycleEvent{{
			Action:    "start",
			Actor:     "local-operator",
			Timestamp: startedAt,
			Detail:    lifecycleStartDetail(spec) + " managed=true",
		}},
	}

	builder := m.managedWorkerCommandBuilder
	if builder == nil {
		builder = defaultManagedWorkerCommand
	}
	cmd, err := builder(effectiveRoot, id, spec)
	if err != nil {
		_ = logFile.Close()
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
		record.FinishedAt = time.Now().UTC()
		_ = m.writeRecord(dir, record)
		return WorkerRecord{}, err
	}
	configureManagedWorkerProcessGroup(cmd)

	logBuf := newLockedBuffer()
	multiLog := io.MultiWriter(logBuf, logFile)
	cmd.Stdout = multiLog
	cmd.Stderr = multiLog

	if err := cmd.Start(); err != nil {
		_ = logFile.Close()
		record.State = "failed"
		record.Status = "failed"
		record.Error = err.Error()
		record.LastError = err.Error()
		record.FinishedAt = time.Now().UTC()
		_ = m.writeRecord(dir, record)
		return WorkerRecord{}, err
	}

	record.PID = cmd.Process.Pid
	if pgid, pgidErr := managedWorkerProcessGroupID(cmd.Process.Pid); pgidErr == nil && pgid > 0 {
		record.PGID = pgid
	} else {
		record.PGID = cmd.Process.Pid
	}
	record.Lifecycle[0].Detail = fmt.Sprintf("%s pid=%d pgid=%d managed=true", lifecycleStartDetail(spec), record.PID, record.PGID)
	_ = m.writeRecord(dir, record)

	progressCh := make(chan agent.ProgressEvent, 16)
	handle := &workerHandle{
		record:       record,
		cancel:       func() {},
		logBuf:       logBuf,
		logFile:      logFile,
		progressCh:   progressCh,
		progressDone: make(chan struct{}),
		lastPhaseTS:  startedAt,
	}

	ctx, cancel := context.WithCancel(context.Background())
	handle.cancel = cancel

	m.mu.Lock()
	m.workers[id] = handle
	m.mu.Unlock()

	m.ensureWatchdog()

	go m.drainProgress(id, handle, progressCh)
	go m.watchManagedWorkerExit(id, dir, handle, cmd)

	return record, nil
}

func defaultManagedWorkerCommand(projectRoot, workerID string, spec ExecuteLoopWorkerSpec) (*exec.Cmd, error) {
	exe, err := os.Executable()
	if err != nil {
		return nil, err
	}

	args := []string{"work", "--no-update-check", "--no-self-refresh", "--server-managed", workerID}
	if strings.TrimSpace(projectRoot) != "" {
		args = append(args, "--project", projectRoot)
	}
	appendManagedString := func(flag, value string) {
		if strings.TrimSpace(value) == "" {
			return
		}
		args = append(args, flag, value)
	}
	appendManagedDuration := func(flag string, d time.Duration) {
		if d <= 0 {
			return
		}
		args = append(args, flag, d.String())
	}

	appendManagedString("--from", spec.FromRev)
	appendManagedString("--harness", spec.Harness)
	appendManagedString("--model", spec.Model)
	appendManagedString("--profile", spec.Profile)
	appendManagedString("--provider", spec.Provider)
	appendManagedString("--effort", spec.Effort)
	appendManagedString("--attempt-backend", spec.AttemptBackend)
	appendManagedString("--label-filter", spec.LabelFilter)
	if spec.IgnoreCooldown {
		args = append(args, "--ignore-cooldown")
		appendManagedString("--reason", spec.CooldownOverrideReason)
	}
	switch spec.Mode {
	case executeloop.ModeOnce:
		args = append(args, "--once")
	case executeloop.ModeWatch:
		args = append(args, "--watch")
		appendManagedDuration("--idle-interval", spec.IdleInterval.Duration)
	}
	if spec.NoReview {
		args = append(args, "--no-review", "--no-review-i-know-what-im-doing")
	}
	appendManagedString("--review-harness", spec.ReviewHarness)
	appendManagedString("--review-model", spec.ReviewModel)
	if spec.MaxCostUSD != 0 {
		args = append(args, "--max-cost", fmt.Sprintf("%g", spec.MaxCostUSD))
	}
	if spec.MaxBeadCostUSD != 0 {
		args = append(args, "--max-bead-cost", fmt.Sprintf("%g", spec.MaxBeadCostUSD))
	}
	if spec.MaxRecoveryCostUSD != 0 {
		args = append(args, "--max-recovery-cost", fmt.Sprintf("%g", spec.MaxRecoveryCostUSD))
	}
	appendManagedDuration("--preclaim-timeout", spec.PreClaimTimeout.Duration)
	appendManagedDuration("--route-resolution-timeout", spec.RouteResolutionTimeout.Duration)
	appendManagedDuration("--request-timeout", spec.RequestTimeout.Duration)
	appendManagedDuration("--rate-limit-max-wait", spec.RateLimitMaxWait.Duration)
	if spec.MinPower != 0 {
		args = append(args, "--min-power", fmt.Sprintf("%d", spec.MinPower))
	}
	if spec.MaxPower != 0 {
		args = append(args, "--max-power", fmt.Sprintf("%d", spec.MaxPower))
	}

	return exec.Command(exe, args...), nil
}

func (m *WorkerManager) watchManagedWorkerExit(id, dir string, handle *workerHandle, cmd *exec.Cmd) {
	waitErr := cmd.Wait()
	close(handle.progressCh)
	<-handle.progressDone

	m.mu.Lock()
	record := handle.record
	preservedState := ""
	if record.State == "stopped" || record.State == "reaped" {
		preservedState = record.State
	}
	record.FinishedAt = time.Now().UTC()
	record.Substate = ""
	if waitErr != nil {
		record.State = "failed"
		record.Status = "failed"

		record.Status = "failed"
		record.Error = waitErr.Error()
		record.LastError = waitErr.Error()
		_ = logFileSync(handle.logFile)
	} else {
		record.State = "exited"
		record.Status = "success"
	}
	if preservedState != "" {
		record.State = preservedState
		record.Status = preservedState
	}
	_ = m.writeRecord(dir, record)
	handle.record = record
	m.mu.Unlock()

	if handle.logFile != nil {
		_ = handle.logFile.Close()
	}
}

