   370	func (m *WorkerManager) StartExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
   371		// Resolve the effective project root: spec override takes priority over the
   372		// manager's default so callers can target any registered project.
   373		effectiveRoot := spec.ProjectRoot
   374		if effectiveRoot == "" {
   375			effectiveRoot = m.projectRoot
   376		}
   377		spec.ProjectRoot = effectiveRoot
