   384		// before creating the worker record or claiming any beads.
   385		// Skipped when OpaquePassthrough=true (ddx work path): routing belongs to
   386		// the agent service; DDx must not pre-resolve or validate the route.
   387		if !spec.OpaquePassthrough {
   388			if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider); err != nil {
   389				return WorkerRecord{}, fmt.Errorf("work: %w", err)
   390			}
   391		}
   392	
   393		if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
   394			return WorkerRecord{}, err
   395		}
   396	
   397		id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
   398		dir := filepath.Join(m.rootDir, id)
   399		if err := os.MkdirAll(dir, 0o755); err != nil {
   400			return WorkerRecord{}, err
   401		}
   402	
   403		// Write spec
   404		specData, _ := json.MarshalIndent(spec, "", "  ")
   405		_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)
   406	
   407		// Open log file
   408		logPath := filepath.Join(dir, "worker.log")
   409		logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
