   412		}
   413	
   414		// Open structured event sink — loop milestones (bead.claimed, bead.result,
   415		// loop.start/end) land here as JSONL so log aggregators and future server
   416		// endpoints can parse them independently of the human-readable worker.log.
   417		eventsPath := filepath.Join(dir, "worker-events.jsonl")
