   434			PollInterval: executeLoopPollInterval(spec).String(),
   435			StdoutPath:   relToProject(m.projectRoot, logPath),
   436			SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
   437			StartedAt:    time.Now().UTC(),
   438		}
   439		record.Lifecycle = append(record.Lifecycle, WorkerLifecycleEvent{
   440			Action:    "start",
   441			Actor:     "local-operator",
   442			Timestamp: record.StartedAt,
   443			Detail:    lifecycleStartDetail(spec),
   444		})
   445		_ = m.writeRecord(dir, record)
   446	
   447		ctx, cancel := context.WithCancel(context.Background())
   448		logBuf := &bytes.Buffer{}
   449		multiLog := io.MultiWriter(logBuf, logFile)
   450	
   451		progressCh := make(chan agent.ProgressEvent, 64)
   452		wakeCh := make(chan struct{}, 1)
   453		handle := &workerHandle{
   454			record:       record,
   455			cancel:       cancel,
   456			logBuf:       logBuf,
   457			logFile:      logFile,
   458			progressCh:   progressCh,
   459			progressDone: make(chan struct{}),
   460			lastPhaseTS:  time.Now().UTC(),
   461			wakeCh:       wakeCh,
   462		}
   463	
   464		m.mu.Lock()
   465		m.workers[id] = handle
   466		m.mu.Unlock()
   467	
   468		m.ensureWatchdog()
   469	
   470		go m.drainProgress(id, handle, progressCh)
   471		go m.runWorker(ctx, id, dir, spec, effectiveRoot, handle, multiLog, eventsFile, progressCh)
   472	
   473		return record, nil
   474	}
