   551	func (m *WorkerManager) runPluginAction(ctx context.Context, id, dir string, spec PluginActionWorkerSpec, handle *workerHandle, log io.Writer, progressCh chan agent.ProgressEvent, run PluginActionExecutor) {
   552		startedAt := time.Now().UTC()
   553		phaseSeq := 1
   554		sendProgress(progressCh, agent.ProgressEvent{
   555			EventID:   "evt-" + randomSuffix(8),
   556			AttemptID: id,
   557			WorkerID:  id,
   558			ProjectID: spec.ProjectRoot,
   559			Phase:     "running",
   560			PhaseSeq:  phaseSeq,
   561			TS:        startedAt,
   562			Message:   fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
   563		})
   564		if log != nil {
   565			_, _ = fmt.Fprintf(log, "%s plugin %s (%s)\n", spec.Action, spec.Name, spec.Scope)
   566		}
   567	
   568		state, err := run(ctx)
   569		if ctxErr := ctx.Err(); ctxErr != nil && err == nil {
   570			err = ctxErr
   571		}
   572	
   573		phase := "done"
   574		message := state
   575		if err != nil {
   576			phase = "failed"
   577			message = err.Error()
   578		}
   579		phaseSeq++
   580		sendProgress(progressCh, agent.ProgressEvent{
   581			EventID:   "evt-" + randomSuffix(8),
   582			AttemptID: id,
   583			WorkerID:  id,
   584			ProjectID: spec.ProjectRoot,
   585			Phase:     phase,
   586			PhaseSeq:  phaseSeq,
   587			TS:        time.Now().UTC(),
   588			ElapsedMS: time.Since(startedAt).Milliseconds(),
   589			Message:   message,
   590		})
   591	
   592		if log != nil {
   593			if err != nil {
   594				_, _ = fmt.Fprintf(log, "failed: %s\n", err)
   595			} else {
   596				_, _ = fmt.Fprintf(log, "completed: %s\n", state)
   597			}
   598		}
   599	
   600		close(progressCh)
   601		<-handle.progressDone
   602	
   603		m.mu.Lock()
   604		record := handle.record
   605		preservedState := ""
   606		if record.State == "stopped" || record.State == "reaped" {
   607			preservedState = record.State
   608		}
   609		record.FinishedAt = time.Now().UTC()
   610		_ = handle.logFile.Close()
   611		if err != nil {
   612			record.State = "failed"
   613			record.Status = "failed"
   614			record.Error = err.Error()
   615			record.LastError = err.Error()
   616		} else {
   617			record.State = "exited"
   618			record.Status = "success"
   619			record.LastResult = &WorkerExecutionResult{
   620				AttemptID:  id,
   621				WorkerID:   id,
   622				PowerClass: "",
   623				Status:     state,
   624				Detail:     fmt.Sprintf("%s plugin %s", spec.Action, spec.Name),
   625			}
   626		}
   627		if preservedState != "" {
   628			record.State = preservedState
   629			record.Status = preservedState
   630		}
   631		_ = m.writeRecord(dir, record)
   632		handle.record = record
   633		m.mu.Unlock()
   634	}
