   647	func nextEscalationFloor(l *powerladder.Ladder, actualPower int) (int, error) {
   648		if l == nil {
   649			return 0, powerladder.ErrLadderExhausted
   650		}
   651		floor := actualPower
   652		for {
   653			next, err := l.Next(floor)
   654			if err == nil {
   655				return next, nil
   656			}
   657			var nvp *powerladder.NoViableProviderError
   658			if errors.As(err, &nvp) {
   659				floor = nvp.Floor
   660				continue
   661			}
   662			return 0, err
   663		}
   664	}
