   666	type tryLoopFloorFinder struct {
   667		ladder *powerladder.Ladder
   668	}
   669	
   670	func (f tryLoopFloorFinder) Next(actualPower int) (int, error) {
   671		return nextEscalationFloor(f.ladder, actualPower)
   672	}
