   674	func runEscalatingPowerAttempts(
   675		ctx context.Context,
   676		initialMinPower int,
   677		ladder *powerladder.Ladder,
   678		attempt func(context.Context, int) (agent.ExecuteBeadReport, error),
   679		recordAttempt func(agent.ExecuteBeadReport),
   680		allowInfrastructureRetry bool,
   681	) (agent.ExecuteBeadReport, error) {
   682		minPower := initialMinPower
   683		floors := tryLoopFloorFinder{ladder: ladder}
   684		for {
   685			report, err := attempt(ctx, minPower)
   686			if recordAttempt != nil && report.BeadID != "" {
   687				recordAttempt(report)
   688			}
   689			if err != nil {
   690				return report, err
   691			}
   692			transition := executeloop.DecideAttemptTransition(executeloop.AttemptTransitionInput{
   693				Status:                   report.Status,
   694				Detail:                   report.Detail,
   695				CurrentMinPower:          minPower,
   696				ActualPower:              report.ActualPower,
   697				Disrupted:                report.Disrupted,
   698				BudgetExhausted:          isBudgetExhaustedFailure(report),
   699				AllowInfrastructureRetry: allowInfrastructureRetry,
   700			}, floors)
   701			if transition.Action != executeloop.TryLoopActionRetryPower {
   702				return report, nil
   703			}
   704			minPower = transition.NextMinPower
   705		}
   706	}
